      "uoc_desc": "Unit of Competence Description (ชื่อหน่วยสมรรถนะ)",
      "eoc_code": "Element of Competence Code (รหัสสมรรถนะย่อย)",
      "eoc_desc": "Element of Competence Description (ชื่อสมรรถนะย่อย)",
